    /**
     * @return array<string, mixed>
     */
    private static function def(
        string $slug,
        string $title,
        string $corridor,
        string $excerpt,
        string $metaTitle,
        string $metaDescription,
        string $metaKeywords,
    ): array {
        return [
            'slug' => $slug,
            'title' => $title,
            'corridor' => $corridor,
            'excerpt' => $excerpt,
            'meta_title' => $metaTitle,
            'meta_description' => $metaDescription,
            'meta_keywords' => $metaKeywords,
        ];
    }

    public static function build(array $definition): string
    {
        $html = self::bodyFor($definition['corridor'], $definition['title'], $definition['slug']);

        return GurgaonBlogContentBuilder::enrichPublic($html, 'corridor_'.$definition['corridor'], [
            'title' => $definition['title'],
            'slug' => $definition['slug'],
        ]);
    }

    private static function bodyFor(string $corridor, string $title, string $slug): string
    {
        $focus = self::corridorFocus($corridor, $slug);

        return self::article(
            $focus['keyword'],
            $focus['intro'],
            $focus['sections'],
        );
    }

    /**
     * @return array{keyword: string, intro: string, sections: list<array{heading: string, paragraphs: list<string>, list?: list<string>}>}
     */
    private static function corridorFocus(string $corridor, string $slug): array
    {
        $map = [
            'golf_course_road' => [
                'keyword' => 'Golf Course Road Gurgaon',
                'intro' => 'Golf Course Road is Gurgaon\'s flagship luxury residential and commercial spine — home to branded towers, golf-facing residences, and proximity to Grade A offices, international schools, and five-star hospitality. Whether you are buying a home, leasing for corporate relocation, or investing for long-term capital preservation, understanding this corridor block-by-block matters more than city-wide averages.',
                'sections' => self::golfSections($slug),
            ],
            'golf_course_extension' => [
                'keyword' => 'Golf Course Extension Road',
                'intro' => 'Golf Course Extension Road extends premium Gurgaon living westward with newer townships, improved internal connectivity, and relative value compared with the main Golf Course Road frontage. Investors and end-users compare possession timelines, developer credibility, and commute to Cyber City before booking here.',
                'sections' => self::extensionSections($slug),
            ],
            'dwarka_expressway' => [
                'keyword' => 'Dwarka Expressway Gurgaon',
                'intro' => 'The Dwarka Expressway corridor is New Gurgaon\'s highest-profile growth belt — linking Gurgaon to Delhi with branded townships, improving retail and schools, and active end-user plus investor interest. Success here depends on choosing the right project phase, not just buying anywhere on the map.',
                'sections' => self::dwarkaSections($slug),
            ],
            'sohna_road' => [
                'keyword' => 'Sohna Road Gurgaon',
                'intro' => 'Sohna Road connects central Gurgaon to southern townships and the Sohna region — offering larger floor plans, competitive per-sq-ft pricing, and rising rental demand as offices and schools expand southward. Buyers weigh commute tolerance against space and value.',
                'sections' => self::sohnaSections($slug),
            ],
            'new_gurgaon' => [
                'keyword' => 'New Gurgaon',
                'intro' => 'New Gurgaon spans sectors and townships along the city\'s expanding western and southern belts — Dwarka Expressway, SPR, and sectors 58–115. It offers space, modern amenities, and entry prices below central DLF and Golf Course Road, with infrastructure still maturing in parts.',
                'sections' => self::newGurgaonSections($slug),
            ],
            'investment_general' => [
                'keyword' => 'Gurgaon property investment',
                'intro' => 'Gurgaon remains one of NCR\'s most liquid property markets — but returns vary sharply by micro-market, product type, and hold period. Smart investors model net yield, resale depth, and possession risk rather than chasing generic "Gurgaon appreciation" headlines.',
                'sections' => self::investmentSections($slug),
            ],
        ];

        return $map[$corridor] ?? $map['investment_general'];
    }

    /**
     * @param  list<array{heading: string, paragraphs: list<string>, list?: list<string>}>  $sections
     */
    private static function article(string $keyword, string $intro, array $sections): string
    {
        $html = '<p>'.$intro.'</p>';
        $html .= '<p>This guide focuses on <strong>'.$keyword.'</strong> with practical advice for end-users, tenants, and investors evaluating Gurgaon in 2026. Ocean Realtors shares registration-backed pricing and verified shortlists — not inflated portal quotes.</p>';

        foreach ($sections as $section) {
            $html .= '<h2>'.htmlspecialchars($section['heading'], ENT_QUOTES, 'UTF-8').'</h2>';
            foreach ($section['paragraphs'] as $paragraph) {
                $html .= '<p>'.$paragraph.'</p>';
            }
            if (! empty($section['list'])) {
                $html .= '<ul>';
                foreach ($section['list'] as $item) {
                    $html .= '<li>'.$item.'</li>';
                }
                $html .= '</ul>';
            }
        }

        $html .= '<h2>How Ocean Realtors Helps</h2>';
        $html .= '<p>Ocean Realtors curates verified options across '.$keyword.' with transparent society comparisons, coordinated site visits, and paperwork screening before token. Call or WhatsApp our Gurgaon desk for a personalised shortlist matched to your budget and timeline.</p>';

        return $html;
    }

