                'list' => ['Old: DLF adjacency, established retail, higher tickets', 'New: townships, highways, larger layouts, possession variance', 'Old: builder floors common', 'New: RERA projects and payment plans'],
            ],
            str_contains($slug, 'investment-opportunities') => ['heading' => 'Investment in New Gurgaon', 'paragraphs' => ['Growth investors target delivered phases with rising resale comps.', 'Avoid over-leveraging on under-construction phases without developer proof points.']],
            str_contains($slug, 'affordable') => ['heading' => 'Affordable Housing in New Gurgaon', 'paragraphs' => ['Entry-level 2 BHK inventory exists on SPR and southern sectors — verify build quality and commute.', 'Payment plans can help first-time buyers if possession dates are credible.']],
            default => ['heading' => 'New Gurgaon Overview', 'paragraphs' => ['New Gurgaon is not one market — Dwarka Expressway, SPR, and southern sectors differ in maturity.', 'Infrastructure completion timelines should drive purchase decisions.']],
        };

        return [
            $focus,
            [
                'heading' => 'Infrastructure and Lifestyle',
                'paragraphs' => ['Schools, hospitals, and malls are filling in but vary by sector — visit surroundings, not just sample flats.', 'Highway access benefits daily commuters to Delhi and Manesar belts.'],
            ],
            [
                'heading' => 'What to Verify Before You Buy',
                'paragraphs' => ['Developer track record, RERA compliance, hidden charges, and realistic possession.', 'Compare ready resale nearby — sometimes delivers better value than new launch brochures.'],
            ],
        ];
    }

    /** @return list<array{heading: string, paragraphs: list<string>, list?: list<string>}>} */
    private static function investmentSections(string $slug): array
    {
        $focus = match (true) {
            str_contains($slug, 'is-gurgaon-good') => ['heading' => 'Is Gurgaon Good for Property Investment?', 'paragraphs' => ['Yes for diversified micro-market strategies — not as a blind city-wide bet.', 'Corporate hub depth, rental demand, and resale liquidity in premium and mid sectors support long-term holds when priced correctly.']],
            str_contains($slug, 'best-investment-sectors') => ['heading' => 'Best Investment Sectors', 'paragraphs' => ['Sectors 56–57, 43–52 belt, New Gurgaon 65–70, and Dwarka Expressway townships rank consistently for depth.', 'Match sector to yield vs appreciation goal — they rarely overlap perfectly.']],
            str_contains($slug, 'high-roi') => ['heading' => 'High ROI Locations', 'paragraphs' => ['ROI is net of maintenance, vacancy, and furnishing — gross yield headlines mislead.', 'Mid Gurgaon and select New Gurgaon phases often beat ultra-luxury on percentage yield while luxury wins on capital safety.']],
            str_contains($slug, 'residential-vs-commercial') => ['heading' => 'Residential vs Commercial', 'paragraphs' => ['Residential suits most individual investors — simpler management and deeper end-user market.', 'Commercial can yield higher rents but needs larger tickets, longer vacancy tolerance, and lease expertise.']],
            str_contains($slug, 'long-term') => ['heading' => 'Long-Term Investment Strategy', 'paragraphs' => ['7–15 year holds align with infrastructure cycles in New Gurgaon and capital preservation in DLF/Golf Course.', 'Rebalance portfolio across one premium and one growth corridor if budget allows.']],
            str_contains($slug, 'rental-yield') => ['heading' => 'Rental Yield in Gurgaon', 'paragraphs' => ['Gross yields of 2.5–4% are common in premium belts; mid sectors can reach higher on right buy-in.', 'Furnished corporate leases improve effective yield but add furnishing depreciation and churn cost.']],
            str_contains($slug, 'forecast') => ['heading' => '2026 Market Forecast', 'paragraphs' => ['Premium central inventory likely stays supply-constrained; New Gurgaon sees competitive new supply.', 'Interest rates and corporate hiring remain macro swing factors for both prices and rents.']],
            str_contains($slug, 'best-time-to-buy') => ['heading' => 'Best Time to Buy', 'paragraphs' => ['Buy when your micro-market shortlist is ready and paperwork clear — not purely on festival calendar myths.', 'Motivated sellers and quarter-end periods sometimes improve negotiation leverage.']],
            str_contains($slug, 'ready-to-move') => ['heading' => 'Ready vs Under-Construction', 'paragraphs' => ['Ready possession eliminates delivery risk and shows true build quality today.', 'Under-construction may offer plans and lower entry but demands developer trust and patience.']],
            str_contains($slug, 'luxury-property-investment') => ['heading' => 'Luxury Property Investment', 'paragraphs' => ['Luxury in Gurgaon means Golf Course Road, DLF Phase 1–2, and top Extension towers.', 'Expect moderate yields with strong resale and tenant quality — not flip-style returns.']],
            default => ['heading' => 'Property Investment Fundamentals in Gurgaon', 'paragraphs' => ['Define hold period, yield target, and risk tolerance before choosing a corridor.', 'Use registration comps and society-level data — not portal averages.']],
        };

        return [
            $focus,
            [
                'heading' => 'Building a Gurgaon Investment Plan',
                'paragraphs' => ['Shortlist three micro-markets; compare one ready resale and one new launch in each.', 'Run net yield and stress-test vacancy at 1–2 months annually.'],
                'list' => ['Premium: capital preservation, corporate tenants', 'Mid sectors: balanced yield and resale', 'New Gurgaon: growth with possession risk', 'Commercial: higher ticket, lease-driven'],
            ],
            [
                'heading' => 'Risk Management',
                'paragraphs' => ['Title and society dues surprises destroy returns — diligence before token is non-negotiable.', 'Avoid over-concentration in a single under-construction project without delivery proof.'],
            ],
        ];
    }
}
